// Calculate days until expiry and match reminder thresholds
const today = new Date();
const thresholds = [60, 30, 7, 0, -30];

return $input.all().flatMap(member => {
  const expiryDate = new Date(member.json.expiry_date);
  const daysUntilExpiry = Math.round((expiryDate - today) / (1000 * 60 * 60 * 24));

  // Check if today matches any reminder threshold
  if (!thresholds.includes(daysUntilExpiry)) {
    return [];
  }

  return [{
    json: {
      ...member.json,
      days_until_expiry: daysUntilExpiry,
      reminder_type: daysUntilExpiry > 0 ? `${daysUntilExpiry}days` : 
                     daysUntilExpiry === 0 ? 'today' : 
                     `${Math.abs(daysUntilExpiry)}days_overdue`
    }
  }];
});

// Generate email content based on reminder type
const days = $json.days_until_expiry;
const member = $json;
let subject, htmlContent;

switch(days) {
  case 60:
    subject = 'CIMA Membership Renewal - 60 Days Notice';
    htmlContent = `<h2>Membership Renewal Notice</h2>
      <p>Dear ${member.full_name},</p>
      <p>Your CIMA membership will expire in <strong>60 days</strong> on ${new Date(member.expiry_date).toLocaleDateString()}.</p>
      <p>As a valued member, you'll continue to enjoy:</p>
      <ul>
        <li>Access to all course materials</li>
        <li>Community forum participation</li>
        <li>Networking opportunities</li>
        <li>Professional development resources</li>
      </ul>
      <p><a href='https://cima.learn/renew'>Renew Your Membership</a></p>
      <p>Thank you for being part of CIMA!</p>
      <p>The CIMA Team</p>`;
    break;

  case 30:
    subject = 'CIMA Membership Renewal - 30 Days Remaining';
    htmlContent = `<h2>Membership Renewal Reminder</h2>
      <p>Dear ${member.full_name},</p>
      <p>Your CIMA membership expires in <strong>30 days</strong> on ${new Date(member.expiry_date).toLocaleDateString()}.</p>
      <p>If you don't renew, you'll lose access to:</p>
      <ul>
        <li>Course enrollment privileges</li>
        <li>Community forum access</li>
        <li>Certificate downloads</li>
        <li>Member-only resources</li>
      </ul>
      <p><strong>Renew now to avoid interruption:</strong> <a href='https://cima.learn/renew'>Renew Membership</a></p>
      <p>The CIMA Team</p>`;
    break;

  case 7:
    subject = 'URGENT: CIMA Membership Expires in 7 Days';
    htmlContent = `<h2>URGENT: Membership Expiring Soon</h2>
      <p>Dear ${member.full_name},</p>
      <p>Your CIMA membership expires in just <strong>7 days</strong> on ${new Date(member.expiry_date).toLocaleDateString()}.</p>
      <p><strong>This is your final reminder!</strong> After expiration, you'll immediately lose access to all member benefits.</p>
      <p><a href='https://cima.learn/renew'><strong>Renew Now</strong></a></p>
      <p>Questions? Call us at 0536735535 or 0241022964.</p>
      <p>The CIMA Team</p>`;
    break;

  case 0:
    subject = 'CIMA Membership Expired Today';
    htmlContent = `<h2>Membership Expired</h2>
      <p>Dear ${member.full_name},</p>
      <p>Your CIMA membership <strong>expired today</strong>.</p>
      <p>You currently cannot access member benefits, but you can reactivate your membership immediately.</p>
      <p><a href='https://cima.learn/renew'><strong>Reactivate Membership</strong></a></p>
      <p>We hope to see you back in the CIMA community soon!</p>
      <p>The CIMA Team</p>`;
    break;

  case -30:
    subject = 'Final Offer: Reactivate Your CIMA Membership';
    htmlContent = `<h2>Final Reactivation Offer</h2>
      <p>Dear ${member.full_name},</p>
      <p>Your CIMA membership expired <strong>30 days ago</strong> on ${new Date(member.expiry_date).toLocaleDateString()}.</p>
      <p>This is your final opportunity to reactivate with your current membership level and benefits.</p>
      <p><a href='https://cima.learn/renew'><strong>Reactivate Now</strong></a></p>
      <p>After this period, you may need to reapply for membership.</p>
      <p>The CIMA Team</p>`;
    break;
}

return [{
  json: {
    ...member,
    email_subject: subject,
    email_html: htmlContent
  }
}];
